import{bQ as a,aL as i,u as t,G as e}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"Redis Cluster","description":"","frontmatter":{},"headers":[],"relativePath":"05.Redis/07-Redis Cluster.md","filePath":"05.Redis/07-Redis Cluster.md","lastUpdated":null}'),l={name:"05.Redis/07-Redis Cluster.md"};function n(p,s,h,d,k,o){return i(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="redis-cluster" tabindex="-1">Redis Cluster <a class="header-anchor" href="#redis-cluster" aria-label="Permalink to &quot;Redis Cluster&quot;">​</a></h1><p>主从和 Sentinel 模式仍然是单主写入——所有写请求都落在同一个主库上，数据容量和写入吞吐受限于单机。Redis Cluster 通过分片把数据分散到多个主节点，每个主节点负责一部分 slot，从而扩大容量和写入吞吐。</p><h2 id="一、16384-个-slot-的分片模型" tabindex="-1">一、16384 个 slot 的分片模型 <a class="header-anchor" href="#一、16384-个-slot-的分片模型" aria-label="Permalink to &quot;一、16384 个 slot 的分片模型&quot;">​</a></h2><p>Redis Cluster 把整个键空间切成 16384 个 slot。每个 key 通过 <code>CRC16(key) % 16384</code> 算出 slot 编号，slot 被分配给各个主节点：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20key%5B%22key%22%5D%20--%3E%20hash%5B%22CRC16(key)%20%25%2016384%22%5D%0A%20%20%20%20hash%20--%3E%20slot%5B%22hash%20slot%22%5D%0A%20%20%20%20slot%20--%3E%20master%5B%22%E8%B4%9F%E8%B4%A3%E8%AF%A5%20slot%20%E7%9A%84%E4%B8%BB%E8%8A%82%E7%82%B9%22%5D%0A%20%20%20%20master%20--%3E%20replica%5B%22%E4%B8%BB%E8%8A%82%E7%82%B9%E5%AF%B9%E5%BA%94%E7%9A%84%E4%BB%8E%E8%8A%82%E7%82%B9%22%5D%0A"></div><p>16384 这个数字的设计考虑：足够多让节点间分片比较均匀，又不太大导致 gossip 协议通信量过大（每个 slot 的迁移状态都需要在节点间传播）。</p><p>slot 是 Cluster 的分片单位，不是节点。节点只是负责一段或多段 slot。扩容、缩容、迁移，本质都是把一部分 slot 从一个主节点挪到另一个主节点。key 属于哪个 slot，决定了它最终落在哪个主节点上。</p><p>分片模型带来的限制：</p><ul><li>多 key 命令（<code>MGET</code>、<code>MSET</code>、<code>SINTER</code> 等）要求所有 key 在同一个 slot。跨 slot 的多 key 操作会报 <code>CROSSSLOT</code> 错误。</li><li>Cluster 只能使用 0 号数据库——<code>SELECT 1</code> 在 Cluster 模式下不可用。单机实例迁移到 Cluster 前，原来靠多个 DB 做逻辑隔离的应用需要改成不同 key 前缀或拆成不同实例。</li></ul><h2 id="二、节点配置和集群总线" tabindex="-1">二、节点配置和集群总线 <a class="header-anchor" href="#二、节点配置和集群总线" aria-label="Permalink to &quot;二、节点配置和集群总线&quot;">​</a></h2><p>每个节点的 Redis 配置：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>port 6379</span></span>
<span class="line"><span>bind 192.168.10.11</span></span>
<span class="line"><span></span></span>
<span class="line"><span>cluster-enabled yes</span></span>
<span class="line"><span>cluster-config-file nodes-6379.conf    # 集群拓扑的自动维护文件，不要手工编辑</span></span>
<span class="line"><span>cluster-node-timeout 15000             # 节点超时判断，默认 15000（15 秒）。设太短网络抖动容易误判，设太长故障检测慢</span></span>
<span class="line"><span></span></span>
<span class="line"><span>appendonly yes</span></span>
<span class="line"><span>dir /data/redis</span></span></code></pre></div><p>除了 6379 端口，Cluster 节点还会占用一个集群总线（cluster bus）端口，默认是 Redis 端口 + 10000，即 <code>16379</code>。总线端口用于节点间的 gossip 通信——交换槽位分配、节点状态和故障检测信息。防火墙放行时两个端口都要开，很多 Cluster 搭建失败就是因为只开了 6379 没开 16379。</p><p>在 Docker、NAT、多网卡或跨网段环境中，节点对外通告的地址需要显式配置，否则 Redis 自动检测到的地址可能是内网 IP 或容器地址，其他节点连不过来：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cluster-announce-ip 192.168.10.11       # 客户端和其他节点实际使用的地址</span></span>
<span class="line"><span>cluster-announce-port 6379</span></span>
<span class="line"><span>cluster-announce-bus-port 16379</span></span></code></pre></div><p>通告地址会影响 <code>MOVED</code> 重定向返回的地址、gossip 通信的目标地址。这里配错时服务端启动正常，客户端却可能被重定向到一个不可达的内网地址。</p><h2 id="三、创建集群" tabindex="-1">三、创建集群 <a class="header-anchor" href="#三、创建集群" aria-label="Permalink to &quot;三、创建集群&quot;">​</a></h2><p>最小生产部署是 3 主 3 从（每个主库有一个从库用于故障转移）：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20TB%0A%20%20%20%20subgraph%20cluster%5B%22Redis%20Cluster%22%5D%0A%20%20%20%20%20%20%20%20m1%5B%22%E4%B8%BB%E8%8A%82%E7%82%B9%2001%3Cbr%2F%3Eslots%200-5460%22%5D%0A%20%20%20%20%20%20%20%20m2%5B%22%E4%B8%BB%E8%8A%82%E7%82%B9%2002%3Cbr%2F%3Eslots%205461-10922%22%5D%0A%20%20%20%20%20%20%20%20m3%5B%22%E4%B8%BB%E8%8A%82%E7%82%B9%2003%3Cbr%2F%3Eslots%2010923-16383%22%5D%0A%20%20%20%20%20%20%20%20r1%5B%22%E4%BB%8E%E8%8A%82%E7%82%B9%2001%3Cbr%2F%3E%E5%A4%8D%E5%88%B6%E4%B8%BB%E8%8A%82%E7%82%B9%2001%22%5D%0A%20%20%20%20%20%20%20%20r2%5B%22%E4%BB%8E%E8%8A%82%E7%82%B9%2002%3Cbr%2F%3E%E5%A4%8D%E5%88%B6%E4%B8%BB%E8%8A%82%E7%82%B9%2002%22%5D%0A%20%20%20%20%20%20%20%20r3%5B%22%E4%BB%8E%E8%8A%82%E7%82%B9%2003%3Cbr%2F%3E%E5%A4%8D%E5%88%B6%E4%B8%BB%E8%8A%82%E7%82%B9%2003%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20m1%20--%3E%20r1%0A%20%20%20%20m2%20--%3E%20r2%0A%20%20%20%20m3%20--%3E%20r3%0A"></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cluster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  192.168.10.11:6379</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  192.168.10.12:6379</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  192.168.10.13:6379</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  192.168.10.14:6379</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  192.168.10.15:6379</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  192.168.10.16:6379</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --cluster-replicas</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span></code></pre></div><p><code>--cluster-replicas 1</code> 表示每个主库配 1 个从库。<code>redis-cli --cluster create</code> 会自动分配主从关系和 16384 个 slot。</p><p>检查集群状态：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.11</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CLUSTER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.11</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CLUSTER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NODES</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cluster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 192.168.10.11:6379</span></span></code></pre></div><p><code>-c</code> 参数表示启用 Cluster 模式——遇到 <code>MOVED</code> 重定向时客户端会自动跳转到正确的节点。</p><p><code>CLUSTER INFO</code> 关键字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>cluster_state</code></td><td>ok 或 fail——集群整体是否可用</td></tr><tr><td><code>cluster_slots_assigned</code></td><td>已分配的 slot 数，正常应该是 16384</td></tr><tr><td><code>cluster_slots_ok</code></td><td>正常服务的 slot 数</td></tr><tr><td><code>cluster_slots_fail</code></td><td>有故障的 slot 数，大于 0 说明某些 slot 无主</td></tr><tr><td><code>cluster_known_nodes</code></td><td>集群已知的总节点数</td></tr></tbody></table><h2 id="四、slot-重定向——moved-和-ask" tabindex="-1">四、slot 重定向——MOVED 和 ASK <a class="header-anchor" href="#四、slot-重定向——moved-和-ask" aria-label="Permalink to &quot;四、slot 重定向——MOVED 和 ASK&quot;">​</a></h2><p>key 不属于当前节点时，Redis 返回重定向。有两种：</p><p><strong>MOVED</strong>：slot 已经确定归属到另一个节点。返回目标节点地址，客户端应该更新自己的 slot-node 映射表，后续请求直接发给正确节点。使用 <code>-c</code> 参数的 <code>redis-cli</code> 会自动处理。</p><p><strong>ASK</strong>：slot 正在迁移中，当前这个 key 暂时在目标节点上。客户端应该只对这次请求发到目标节点，不要更新映射表——因为 slot 还没迁移完，其他 key 可能还在当前节点。</p><p>查看 key 属于哪个 slot：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CLUSTER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> KEYSLOT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1001</span></span></code></pre></div><p>应用接入 Cluster 时要用支持 Cluster 的客户端（JedisCluster、Lettuce 的 Cluster 模式等）。把 Cluster 当单机 Redis 连，很快就会遇到 MOVED 错误。</p><h2 id="五、hash-tag——让多个-key-落在同一个-slot" tabindex="-1">五、Hash Tag——让多个 key 落在同一个 slot <a class="header-anchor" href="#五、hash-tag——让多个-key-落在同一个-slot" aria-label="Permalink to &quot;五、Hash Tag——让多个 key 落在同一个 slot&quot;">​</a></h2><p>Cluster 下跨 slot 的多 key 命令会报错。如果确实需要把某几个 key 放一起操作（比如一个用户的多个属性），可以用 hash tag 控制它们落入同一个 slot：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CLUSTER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> KEYSLOT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;user:{1001}:profile&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CLUSTER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> KEYSLOT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;user:{1001}:tokens&#39;</span></span></code></pre></div><p>花括号 <code>{}</code> 里的内容参与 CRC16 计算，所以 <code>user:{1001}:profile</code> 和 <code>user:{1001}:tokens</code> 会落在同一个 slot，<code>MGET</code> 就能用了。</p><p>hash tag 只适合少量确实需要一起操作的 key。如果滥用——比如所有 key 都用 <code>{common}</code> 标签——大量数据会集中到一个 slot，Cluster 的分片效果就被抵消了，那个 slot 所在节点成为热点。</p><h2 id="六、扩容——加节点-迁移-slot" tabindex="-1">六、扩容——加节点 + 迁移 slot <a class="header-anchor" href="#六、扩容——加节点-迁移-slot" aria-label="Permalink to &quot;六、扩容——加节点 + 迁移 slot&quot;">​</a></h2><p>扩容分两步：加节点，然后迁移一部分 slot 到新节点。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. 把新节点加入集群</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cluster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add-node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 192.168.10.17:6379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 192.168.10.11:6379</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. 迁移 slot 到新节点（交互式）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cluster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reshard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 192.168.10.11:6379</span></span></code></pre></div><p><code>reshard</code> 会交互询问：迁移多少 slot、目标节点是哪个、从哪里迁。迁移过程中 slot 状态在 importing/migrating 之间切换，客户端可能遇到 <code>ASK</code> 重定向——Cluster 客户端会处理，但延迟可能略有上升。所以扩容窗口要观察应用错误率和延迟。</p><h2 id="七、缩容——先迁走-slot-再删节点" tabindex="-1">七、缩容——先迁走 slot，再删节点 <a class="header-anchor" href="#七、缩容——先迁走-slot-再删节点" aria-label="Permalink to &quot;七、缩容——先迁走 slot，再删节点&quot;">​</a></h2><p>缩容不能直接停节点——节点上有 slot，停了那些 slot 就不可用了。要先迁移 slot：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. 迁移节点上的所有 slot 到其他节点</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cluster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reshard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 192.168.10.11:6379</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. 确认节点没有 slot</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CLUSTER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NODES</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.17</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. 删除节点</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cluster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> del-node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 192.168.10.11:6379</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">node-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p><code>node-id</code> 从 <code>CLUSTER NODES</code> 输出里获取——那串 40 字符的十六进制 ID。</p><h2 id="八、故障转移" tabindex="-1">八、故障转移 <a class="header-anchor" href="#八、故障转移" aria-label="Permalink to &quot;八、故障转移&quot;">​</a></h2><p>Cluster 自带故障检测和转移。主库故障后，如果它有从库，集群会选举一个从库提升为主库，接管故障主库的 slot。</p><p>手工触发切换（用于维护窗口）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在从库上执行，让它接管主库角色</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.14</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6379</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CLUSTER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> FAILOVER</span></span></code></pre></div><p><code>CLUSTER FAILOVER</code> 和 <code>CLUSTER FAILOVER FORCE</code> 的区别：前者是协商式，从库先和主库同步到最新再切换（数据安全优先）；后者是强制式，从库不等同步完成直接提升（可用性优先，但可能丢数据）。</p><p>Cluster 的故障转移依赖多数主库能互相通信。网络分区时，少数派一侧的主库无法形成多数，会被认为故障——少数派一侧的从库也不会被提升。这是 Cluster 可用性模型的核心设计：宁可拒绝服务，也不产生两个互相不知道的&quot;多数派&quot;各自写数据（脑裂）。</p><h2 id="九、常见问题" tabindex="-1">九、常见问题 <a class="header-anchor" href="#九、常见问题" aria-label="Permalink to &quot;九、常见问题&quot;">​</a></h2><h3 id="moved-错误" tabindex="-1">MOVED 错误 <a class="header-anchor" href="#moved-错误" aria-label="Permalink to &quot;MOVED 错误&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MOVED 3999 192.168.10.12:6379</span></span></code></pre></div><p>客户端不支持 Cluster（没有自动重定向）、<code>cluster-announce-ip</code> 配置错误导致返回了不可达地址、或者 slot 正在迁移中。排查顺序：先看客户端是否用了 Cluster 模式，再看 <code>CLUSTER NODES</code> 里通告的地址是否可达。</p><h3 id="clusterdown" tabindex="-1">CLUSTERDOWN <a class="header-anchor" href="#clusterdown" aria-label="Permalink to &quot;CLUSTERDOWN&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CLUSTERDOWN The cluster is down</span></span></code></pre></div><p>集群整体不可用。原因：有 slot 没有分配（<code>cluster_slots_assigned != 16384</code>）、有 slot 的负责主库全部故障且无从库、多数主库之间无法通信（网络分区）。先 <code>CLUSTER INFO</code> 看 <code>cluster_slots_ok</code> 和 <code>cluster_slots_fail</code>，再 <code>CLUSTER NODES</code> 看哪些节点被标记了 <code>fail</code>。</p><h3 id="crossslot" tabindex="-1">CROSSSLOT <a class="header-anchor" href="#crossslot" aria-label="Permalink to &quot;CROSSSLOT&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CROSSSLOT Keys in request don&#39;t hash to the same slot</span></span></code></pre></div><p>多 key 命令涉及的 key 不在同一个 slot。要么拆成单 key 命令分别执行，要么用 hash tag 让它们落到同一个 slot。</p><h3 id="select-不可用" tabindex="-1">SELECT 不可用 <a class="header-anchor" href="#select-不可用" aria-label="Permalink to &quot;SELECT 不可用&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ERR SELECT is not allowed in cluster mode</span></span></code></pre></div><p>Cluster 只有 0 号数据库。应用配置里如果指定了 <code>database: 1</code>，迁移到 Cluster 后会直接报这个错。</p><h2 id="十、巡检要点" tabindex="-1">十、巡检要点 <a class="header-anchor" href="#十、巡检要点" aria-label="Permalink to &quot;十、巡检要点&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cluster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 192.168.10.11:6379</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.11</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CLUSTER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.11</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CLUSTER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NODES</span></span></code></pre></div><p>巡检关注：</p><table tabindex="0"><thead><tr><th>检查项</th><th>正常标准</th></tr></thead><tbody><tr><td>slot 覆盖率</td><td><code>cluster_slots_assigned</code> = 16384，<code>cluster_slots_fail</code> = 0</td></tr><tr><td>主库数量</td><td>和拓扑设计一致</td></tr><tr><td>从库分布</td><td>从库和对应主库在不同机器上（否则机器挂了主从一起挂）</td></tr><tr><td>节点状态</td><td>无 <code>fail</code> 标记的节点</td></tr><tr><td>迁移状态</td><td>无残留的 importing/migrating slot</td></tr></tbody></table>`,69)])])}const F=a(l,[["render",n]]);export{c as __pageData,F as default};
